 Begin SlaMap 	# Conversion between sky coordinate systems
    Nin = 2 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    Nsla = 2 	# Number of conversion steps
    Sla1 = "PREC" 	# Apply IAU 1975 (FK5) precession
    Sla1a = 1950 	# From Julian epoch
    Sla1b = 1975 	# To Julian epoch
    Sla2 = "PREC" 	# Apply IAU 1975 (FK5) precession
    Sla2a = 2000 	# From Julian epoch
    Sla2b = 2025 	# To Julian epoch
 End SlaMap
